mapper.select:
SELECT br.id, br.reader_id AS readerId, r.reader_no AS readerNo, r.name AS readerName, br.book_id AS bookId, b.book_code AS bookCode, b.title AS bookTitle, b.author AS author, br.borrow_date AS borrowDate, br.due_date AS dueDate, br.return_date AS returnDate, br.overdue_days AS overdueDays, br.renew_count AS renewCount, br.status, CASE WHEN br.status = 0 AND br.due_date < CURDATE() THEN TRUE ELSE FALSE END AS overdue, br.create_time AS createTime FROM library_borrow_record br LEFT JOIN library_reader r ON br.reader_id = r.id LEFT JOIN library_book b ON br.book_id = b.id
AND br.reader_id = #{query.readerId}
AND br.book_id = #{query.bookId}
AND br.status = #{query.status}
AND br.status = 0 AND br.due_date < CURDATE() AND br.return_date IS NULL
ORDER BY br.id DESC
